eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   LEVELS: () => (/* binding */ LEVELS),\n/* harmony export */   getLevelForXP: () => (/* binding */ getLevelForXP),\n/* harmony export */   getLevelProgress: () => (/* binding */ getLevelProgress),\n/* harmony export */   getXPToNextLevel: () => (/* binding */ getXPToNextLevel)\n/* harmony export */ });\n// Pass the UK Test — XP Level Thresholds\n// 20 levels with titles themed around the Life in the UK journey\nconst LEVELS = [\n    {\n        level: 1,\n        title: \"Newcomer\",\n        xpRequired: 0\n    },\n    {\n        level: 2,\n        title: \"Curious Learner\",\n        xpRequired: 100\n    },\n    {\n        level: 3,\n        title: \"Apprentice\",\n        xpRequired: 250\n    },\n    {\n        level: 4,\n        title: \"Keen Student\",\n        xpRequired: 500\n    },\n    {\n        level: 5,\n        title: \"Historian\",\n        xpRequired: 800\n    },\n    {\n        level: 6,\n        title: \"Civic Aware\",\n        xpRequired: 1200\n    },\n    {\n        level: 7,\n        title: \"Debater\",\n        xpRequired: 1700\n    },\n    {\n        level: 8,\n        title: \"Resident Scholar\",\n        xpRequired: 2300\n    },\n    {\n        level: 9,\n        title: \"Law Abider\",\n        xpRequired: 3000\n    },\n    {\n        level: 10,\n        title: \"Patriot\",\n        xpRequired: 4000\n    },\n    {\n        level: 11,\n        title: \"Heritage Keeper\",\n        xpRequired: 5200\n    },\n    {\n        level: 12,\n        title: \"Cultural Expert\",\n        xpRequired: 6500\n    },\n    {\n        level: 13,\n        title: \"Institution Know-It-All\",\n        xpRequired: 8000\n    },\n    {\n        level: 14,\n        title: \"Parliamentary Sage\",\n        xpRequired: 9700\n    },\n    {\n        level: 15,\n        title: \"History Buff\",\n        xpRequired: 11500\n    },\n    {\n        level: 16,\n        title: \"Commonwealth Scholar\",\n        xpRequired: 13500\n    },\n    {\n        level: 17,\n        title: \"Royal Advisor\",\n        xpRequired: 16000\n    },\n    {\n        level: 18,\n        title: \"Brexit Survivor\",\n        xpRequired: 19000\n    },\n    {\n        level: 19,\n        title: \"True Brit\",\n        xpRequired: 22500\n    },\n    {\n        level: 20,\n        title: \"Citizenship Champion\",\n        xpRequired: 27000\n    }\n];\n// Returns current level object for a given XP total\nfunction getLevelForXP(xp) {\n    let current = LEVELS[0];\n    for (const lvl of LEVELS){\n        if (xp >= lvl.xpRequired) current = lvl;\n        else break;\n    }\n    return current;\n}\n// Returns XP needed to reach the next level (null if max level)\nfunction getXPToNextLevel(xp) {\n    const current = getLevelForXP(xp);\n    const nextLevel = LEVELS.find((l)=>l.level === current.level + 1);\n    if (!nextLevel) return null;\n    return nextLevel.xpRequired - xp;\n}\n// Returns progress percentage toward next level (0-100)\nfunction getLevelProgress(xp) {\n    const current = getLevelForXP(xp);\n    const nextLevel = LEVELS.find((l)=>l.level === current.level + 1);\n    if (!nextLevel) return 100;\n    const range = nextLevel.xpRequired - current.xpRequired;\n    const earned = xp - current.xpRequired;\n    return Math.round(earned / range * 100);\n}\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./src/data/levels.js\n");

